INSERT INTO square_post (user_id, title, question, answer, view_count, like_count, status, created_at, updated_at, deleted) VALUES
(3, '大一高数怎么学才能不挂科？', '马上期末了，高数完全听不懂，有没有高效的学习方法推荐？', '大一高数其实没那么可怕，给你几个实用建议：\n\n1. **抓重点**：极限、导数、积分三大块是考试核心，先把这三章的课后题做透\n2. **看视频**：B站搜"宋浩老师高数"，讲得比我们老师清楚\n3. **做题是关键**：只看不练等于白学，至少把近三年期末卷子各做两遍\n4. **不要背公式**：理解推导过程，公式自然就记住了\n\n加油！', 328, 24, 1, NOW() - INTERVAL 15 DAY, NOW() - INTERVAL 15 DAY, 0),
(3, '四六级和考研英语可以同时准备吗？', '大三了，想先考六级再准备考研，两个一起准备会不会冲突？', '完全可以一起准备，而且六级考得好对考研也有帮助！\n\n**建议策略**：\n- 上半年主攻六级（6月考试），重点背六级词汇\n- 六级考完无缝衔接考研英语，词汇量已经打好基础了\n- 阅读习惯已经培养好，考研阅读只需要适应题型\n\n**注意**：六级和考研英语最大区别是——六级有听力，考研没有。所以上半年的听力训练别落下。', 256, 18, 1, NOW() - INTERVAL 12 DAY, NOW() - INTERVAL 12 DAY, 0),
(2, '选修课选什么比较轻松又有趣？', '公选课学分还没够，有没有既好过又实用的课程推荐？', '推荐几门往年评价很好的课：\n\n1. **心理学与生活**：李心怡老师，课上有很多有趣的心理实验，考试开卷\n2. **短视频创作**：王思涵老师，教你剪辑、运镜，期末交一个作品就行\n3. **日语入门**：刘洋老师，从五十音开始教，适合零基础\n4. **摄影基础**：赵老师，带你去校园实拍，期末交组照片\n\n建议避开周一早八和周五下午的课，人少竞争小。', 489, 36, 1, NOW() - INTERVAL 10 DAY, NOW() - INTERVAL 10 DAY, 0),
(4, '校园网经常断怎么办？', '宿舍校园网打游戏老掉线，有什么解决办法？', '校园网确实不太稳定，几个方案：\n\n1. **用网线**：比 WiFi 稳定得多，宿舍桌上有网口\n2. **错峰上网**：晚上8-11点是高峰期，打排位尽量避坑\n3. **备用流量**：办个校园流量卡，关键时候切移动数据\n4. **报修**：如果只是你宿舍的问题，打电话 8888-1234 报修\n\n如果是整个楼的问题，那就是设备故障，等学校修吧。', 187, 12, 1, NOW() - INTERVAL 8 DAY, NOW() - INTERVAL 8 DAY, 0),
(6, '考研自习室占座攻略？', '图书馆考研专区位置太少了，有什么占座技巧？', '考研党血泪经验：\n\n1. **早上6:30前到**：7点后基本无座\n2. **别占座**：现在有座位预约系统了！扫桌上二维码在线预约，能约一整天\n3. **备选地点**：教学楼空教室、食堂三楼自习区（知道的人少）\n4. **和研友轮流**：组个3人群，每天轮一个人早到\n\n其实效率比位置重要，找个通风好、光线足的地方就行。', 612, 45, 1, NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 5 DAY, 0),
(2, '有没有靠谱的二手教材购买渠道？', '新学期买教材太贵了，想买二手的，哪里比较靠谱？', '几大渠道给你整理好了：\n\n1. **校圈二手市场**（就是这里！）：同学直接出，当面交易最放心\n2. **学长学姐传承**：每年毕业季有跳蚤市场，教材半卖半送\n3. **孔夫子旧书网**：专业教材很全，注意看品相描述\n4. **打印店**：部分教材有 PDF 版，成本只要十几块（低调）\n\n买之前确认版本和 ISBN，别买错版次了。', 345, 29, 1, NOW() - INTERVAL 3 DAY, NOW() - INTERVAL 3 DAY, 0),
(3, '食堂哪个窗口最值得吃？', '吃了两个月食堂，有些窗口还没试过，求推荐隐藏美食！', '作为一个吃了四年食堂的毕业狗，给你列个必吃清单：\n\n1. **一食堂二楼麻辣香锅**：人均15，微辣就好，必加土豆片和午餐肉\n2. **二食堂兰州拉面**：手工现拉，汤底是熬的，不是料包！\n3. **三食堂煲仔饭**：腊味双拼最经典，锅巴是灵魂\n4. **小吃街鸡蛋灌饼**：加辣条加里脊，六块钱的快乐\n\n避雷：一食堂三楼的西餐窗口，贵且难吃。', 892, 67, 1, NOW() - INTERVAL 1 DAY, NOW() - INTERVAL 1 DAY, 0),
(6, '学分不够只剩一学期了怎么办？', '突然发现选修课学分还差4分，这学期还能补上吗？', '来得及但得抓紧：\n\n1. **查教务系统**：看看还有哪些课没满，加课申请还开着\n2. **网课学分**：智慧树、超星尔雅上的课计入公选课学分\n3. **创新创业学分**：参加大创项目、发表论文可以抵学分\n4. **找辅导员**：紧急情况可以申请特殊加课\n\n4分=两门课，这学期安排好，下期压力小。别拖到最后一学期了！', 234, 15, 1, NOW() - INTERVAL 2 DAY, NOW() - INTERVAL 2 DAY, 0),
(2, 'Java和Python先学哪个？', '计算机专业大一，不知道该先深入Java还是Python，求指点。', '这个问题被问烂了，给你最实用的建议：\n\n**如果为了找工作**：先学 Java\n- 校招需求量最大，Spring Boot 全家桶是面试标配\n- 数据结构、算法、多线程这些面试重点，Java 资料最全\n\n**如果为了做项目**：先学 Python\n- 语法简单，几周就能上手\n- AI、爬虫、数据分析方向很香\n\n**我的建议**：大一学 Python 打好编程思维，大二转 Java 深入企业级开发。\n\nPython 让你爱上编程，Java 让你找到工作。', 534, 42, 1, NOW() - INTERVAL 4 DAY, NOW() - INTERVAL 4 DAY, 0),
(4, '体测800米怎么跑及格？', '从小体育就拉胯，800米每次都跑不下来，有训练方法吗？', '临时抱佛脚版训练计划（4周）：\n\n**第1周**：每天慢跑2公里，不求速度，只要不停\n**第2周**：隔天跑400米×3组，组间休息2分钟\n**第3周**：隔天跑600米×2组，配速比目标快10秒\n**第4周**：隔天完整跑一次800米，调整呼吸节奏\n\n**考试当天**：\n- 前30分钟吃半根香蕉\n- 前10分钟做动态拉伸（别坐着不动）\n- 前400米跟住大部队，后400米靠意志力\n\n你能行的！', 423, 31, 1, NOW() - INTERVAL 7 DAY, NOW() - INTERVAL 7 DAY, 0),
(5, '校园贷的坑怎么识别？', '最近校园里好多贷款广告，怎么判断是不是坑？', '很严肃的话题，记住三条铁律：\n\n1. **任何让你先交钱的贷款都是诈骗**——保证金、手续费、解冻费全是套路\n2. **年利率超过24%就是高利贷**——算一下，借1000还1500就是高利贷\n3. **裸贷、培训贷、美容贷都是坑**——尤其是"免费培训包就业"那种\n\n**急需用钱怎么办**：\n- 找辅导员申请临时困难补助\n- 申请学校助学贷款（正规，利息很低）\n- 去正规银行办校园信用卡（工行/建行都有学生卡）\n\n千万别碰网贷，利滚利能翻几十倍。', 678, 53, 1, NOW() - INTERVAL 6 DAY, NOW() - INTERVAL 6 DAY, 0),
(3, '如何拿到大厂实习offer？', '大三暑假想去大厂实习，现在该怎么准备？', '按时间线给你规划：\n\n**大三上（现在）**：\n- 刷 LeetCode 100 题（简单50+中等50）\n- 做一个拿得出手的项目（Spring Boot + Vue 这种就很加分）\n- 整理简历，突出项目经验\n\n**大三寒假**：\n- 投递春招实习（2-4月是投递高峰期）\n- 牛客网上看面经，刷对应公司的常考题\n\n**面试阶段**：\n- 八股文背熟（JVM/并发/网络/数据库）\n- 项目经历能讲清楚架构、难点、解决方案\n\n**关键**：第一份实习不一定要去BAT，中厂干3个月积累经验，秋招再冲大厂。', 756, 58, 1, NOW() - INTERVAL 9 DAY, NOW() - INTERVAL 9 DAY, 0),
(2, '宿舍养宠物被抓会怎样？', '偷偷在宿舍养了只仓鼠，被宿管发现了会有什么后果？', '说真的，赶紧送走吧。\n\n**可能的后果**：\n1. 通报批评+取消年度评优资格\n2. 写检讨+打扫宿舍楼一周\n3. 严重的话记过处分（影响毕业）\n\n**为什么不让养**：\n- 异味影响室友\n- 动物毛发引起过敏\n- 假期没人管会饿死\n\n**替代方案**：\n- 养多肉植物（解压还不违规）\n- 去学校流浪猫救助站当志愿者\n\n把仓鼠送给能好好养的人吧，别等宿管敲门。', 156, 11, 1, NOW() - INTERVAL 14 DAY, NOW() - INTERVAL 14 DAY, 0),
(6, '毕业论文选题怎么选？', '马上大四了，论文选题毫无头绪，导师也不管，怎么办？', '几点建议：\n\n1. **选你导师擅长的方向**：这样他能指导你，答辩委员会也不会刁难\n2. **选资料好找的**：选题之前先去知网搜一下，相关论文少于20篇的别碰\n3. **选你能实现的**：计算机专业做系统开发 > 理论研究（更容易出成果）\n\n**推荐选题模式**："基于XXX技术的XXX系统设计与实现"\n- 基于 Spring Boot 的校园二手交易系统（这不现成的？）\n- 基于深度学习的课堂专注度检测系统\n\n**时间线**：大四上确定题目 → 寒假写开题报告 → 3月写初稿 → 4月修改 → 5月答辩。', 445, 33, 1, NOW() - INTERVAL 11 DAY, NOW() - INTERVAL 11 DAY, 0),
(4, '学校附近有没有好玩的？', '周末想出去玩，学校周边有什么值得去的地方？', '周边一日游推荐：\n\n1. **大学城小吃街**：从学校北门坐公交15分钟，夜市超热闹\n2. **XX湖公园**：春天樱花季巨美，划船20块一小时\n3. **XX山**：爬山2小时登顶，看日出要凌晨3点出发\n4. **XX商业街**：逛街看电影一条龙，晚上有街头艺人表演\n\n**交通**：公交2块钱随便坐，打车也不贵，拼车更便宜。\n\n周末别宅宿舍，出去走走！', 534, 41, 1, NOW() - INTERVAL 2 DAY, NOW() - INTERVAL 2 DAY, 0),
(3, '怎么跟室友处好关系？', '和三个室友作息不同，一个打游戏到半夜，一个早上6点闹钟响不停，心累。', '宿舍关系是大学必修课：\n\n1. **开宿舍会议**：心平气和地讨论作息规则，定个熄灯时间和安静时段\n2. **耳塞+眼罩**：解决不了别人的问题就保护好自己的睡眠\n3. **别说闲话**：有问题当面说，别在背后抱怨\n4. **偶尔一起吃饭**：一起撸串是化解矛盾的最佳方式\n\n**如果实在解决不了**：\n- 图书馆是最好的避风港\n- 申请换宿舍（但这是最后手段）\n\n记住：室友不一定要成为朋友，互相尊重就够。', 289, 22, 1, NOW() - INTERVAL 3 DAY, NOW() - INTERVAL 3 DAY, 0),
(2, '助学金申请需要什么材料？', '家里条件不太好，想申请助学金，具体要准备什么？', '标准流程：\n\n1. **贫困证明**：村委会/社区开的家庭经济困难证明（盖章）\n2. **家庭情况调查表**：学校发的，如实填写\n3. **申请书**：手写，说明家庭情况和申请理由，500字左右\n4. **相关证件**：低保证、残疾证、病历等（如果有的话）\n\n**时间节点**：\n- 每年9月开学后两周内提交\n- 先班级评议 → 学院审核 → 学校公示\n\n金额一般是每年2000-4000元。还有勤工助学岗位（图书馆、食堂、办公室），有意向可以同步申请。\n\n别不好意思，这是国家给的福利！', 178, 14, 1, NOW() - INTERVAL 13 DAY, NOW() - INTERVAL 13 DAY, 0),
(5, '学校VPN怎么用？', '放假回家想查论文，学校VPN怎么配置？', '校外访问校内资源三步：\n\n1. **下载客户端**：学校官网→信息中心→VPN服务→下载对应系统版本\n2. **登录**：地址 vpn.campus.edu.cn，账号是学号，密码是统一认证密码\n3. **访问资源**：连接成功后就能访问知网、万方、Web of Science 等数据库\n\n**常见问题**：\n- 连不上？检查是否开了其他代理软件\n- 下载慢？凌晨速度快\n- 忘记密码？带学生证去信息中心重置\n\n手机也能用，App Store 搜学校名找。', 234, 16, 1, NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 5 DAY, 0),
(3, '学生会值得加入吗？', '大一新生，好多人拉我进学生会，到底值不值得？', '实话实说，有利有弊：\n\n**好处**：\n- 锻炼沟通和组织能力\n- 认识不同专业的朋友\n- 评奖学金有加分\n\n**弊端**：\n- 占用大量课余时间\n- 有些部门形式主义严重\n- 大二以后学业压力上来会很累\n\n**建议**：\n- 加1个感兴趣的部门就够了，别贪多\n- 大一体验一年，大二决定要不要留任\n- 技术类专业的学生，实验室/竞赛比学生会更有价值\n\n说白了，学生会对保研加分有用，但增长不了硬技能。', 456, 35, 1, NOW() - INTERVAL 8 DAY, NOW() - INTERVAL 8 DAY, 0),
(6, '怎么在大学里脱单？', '单身两年了，感觉大学不谈恋爱就亏了，但又不知道怎么开始。', '不贩卖焦虑，给你实在建议：\n\n1. **先把自己收拾好**：干净、得体、有礼貌，这已经超过80%的男生了\n2. **扩大社交圈**：选修课、社团、志愿活动，别整天宅宿舍打游戏\n3. **别目的性太强**：先做朋友，自然相处，别一上来就问"处对象吗"\n4. **学会聊天**：多听少说，真诚比套路有用\n\n**常见误区**：\n- 表白不是发起冲锋的号角，是胜利后的凯歌（时机成熟再表白）\n- 别当舔狗，感动自己感动不了别人\n- 大学不谈恋爱不会死，但错过成长会后悔\n\n先变优秀，爱情自然会来。', 987, 76, 1, NOW() - INTERVAL 1 DAY, NOW() - INTERVAL 1 DAY, 0);
INSERT INTO market_item (user_id, title, description, price, original_price, category, `condition`, images, status, view_count, like_count, created_at, updated_at, deleted) VALUES
(3, '机械键盘 IKBC C87 青轴', '用了半年，手感无敌，就是室友嫌太吵了。换了个静音红轴所以出。配件齐全，原装键帽没用过。', 120.00, 299.00, '数码', 'USED', '[]', 'ON_SALE', 156, 12, NOW() - INTERVAL 20 DAY, NOW() - INTERVAL 20 DAY, 0),
(2, '高等数学第七版（上下册）', '大一用的，有笔记但很整洁。上册9成新，下册全新没翻过（别问为什么）。', 25.00, 68.00, '教材', 'USED', '[]', 'ON_SALE', 89, 8, NOW() - INTERVAL 18 DAY, NOW() - INTERVAL 18 DAY, 0),
(4, 'iPad 第九代 64G WIFI版', '考研党必备，买来只看网课做笔记，没打过游戏。屏幕贴了类纸膜，带一支 Apple Pencil 一代。', 1800.00, 3299.00, '数码', 'LIKE_NEW', '[]', 'SOLD', 267, 25, NOW() - INTERVAL 15 DAY, NOW() - INTERVAL 15 DAY, 0),
(6, '考研英语真题 2025版（全新未拆）', '买多了，多出一套。黄皮书全套，英语二，含历年真题+解析+词汇。', 35.00, 89.00, '教材', 'NEW', '[]', 'ON_SALE', 112, 9, NOW() - INTERVAL 12 DAY, NOW() - INTERVAL 12 DAY, 0),
(2, '小电煮锅 1.5L', '宿舍偷偷煮泡面的神器！功率只有300W，宿管来了拔了藏起来就行。九成新。', 18.00, 49.00, '生活', 'USED', '[]', 'SOLD', 203, 18, NOW() - INTERVAL 10 DAY, NOW() - INTERVAL 10 DAY, 0),
(3, '雷蛇鼠标 DeathAdder Essential', '手感很好，就是买了无线版所以出掉。有线白色，用了一年。', 60.00, 199.00, '数码', 'USED', '[]', 'ON_SALE', 78, 6, NOW() - INTERVAL 8 DAY, NOW() - INTERVAL 8 DAY, 0),
(4, '床上书桌 折叠款', '懒人必备，床上写作业神器。稳固不晃，带杯架和手机槽。毕业了带不走。', 30.00, 89.00, '生活', 'USED', '[]', 'ON_SALE', 134, 10, NOW() - INTERVAL 7 DAY, NOW() - INTERVAL 7 DAY, 0),
(6, 'Java核心技术 卷1（第12版）', '经典Java入门书，翻过一遍有很多标注。学完基本能上手Spring Boot了。', 40.00, 149.00, '教材', 'USED', '[]', 'ON_SALE', 92, 7, NOW() - INTERVAL 5 DAY, NOW() - INTERVAL 5 DAY, 0),
(2, '吉他 Yamaha F310 民谣吉他', '入门神器，买来学了一个月放弃了。琴弦新换的，送调音器和教材。', 350.00, 899.00, '兴趣', 'LIKE_NEW', '[]', 'ON_SALE', 178, 14, NOW() - INTERVAL 4 DAY, NOW() - INTERVAL 4 DAY, 0),
(3, '台灯 护眼LED 三档调光', '大一带的，现在换了屏幕挂灯，这个不用了。灯光柔和，三档亮度+暖白两色。', 25.00, 79.00, '生活', 'USED', '[]', 'ON_SALE', 67, 5, NOW() - INTERVAL 3 DAY, NOW() - INTERVAL 3 DAY, 0),
(4, '公路自行车 捷安特 Escape 3', '买了电动车后基本没骑过了。S码，适合165-175身高。送水壶架和密码锁。', 800.00, 2398.00, '运动', 'USED', '[]', 'ON_SALE', 312, 28, NOW() - INTERVAL 2 DAY, NOW() - INTERVAL 2 DAY, 0),
